import pytest
import requests

BASE_URL = "http://localhost:8080"

def test_create_observation_valid_loinc_code_returns_201(clinician_auth_headers, existing_patient_id):
    payload = {
        "resourceType": "Observation",
        "status": "preliminary",
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": "8867-4",
                    "display": "Heart rate"
                }
            ]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    resp = requests.post(
        f"{BASE_URL}/Observation",
        json=payload,
        headers=clinician_auth_headers
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body["resourceType"] == "Observation"
    assert "id" in body
    assert body["code"]["coding"][0]["system"] == "http://loinc.org"

